const url = process.env.DIRECT_URL || process.env.DATABASE_URL;
if (!url) throw new Error('No database URL loaded');
const sql = postgres(url, { max: 1 });
try {
  const [job] = await sql`
    SELECT id FROM job_runs
    WHERE trigger_run_id = 'run_cmqefjl0h1jif0olkl3kkpjk9'
    ORDER BY started_at DESC
    LIMIT 1
  `;
  const [batch] = await sql`
    SELECT id, status, error, model_run_id
    FROM extraction_batches
    WHERE job_run_id = ${job.id}
    ORDER BY created_at DESC
    LIMIT 1
  `;
  const failures = await sql`
    SELECT ev.check_name, ev.status, ev.detail, count(*)::int AS count
    FROM extraction_validation_results ev
    JOIN extraction_candidates c ON c.id = ev.candidate_id
    WHERE c.extraction_batch_id = ${batch.id}
      AND ev.status = 'fail'
    GROUP BY ev.check_name, ev.status, ev.detail
    ORDER BY count DESC
    LIMIT 12
  `;
  const candidates = await sql`
    SELECT status, validation_error, count(*)::int AS count
    FROM extraction_candidates
    WHERE extraction_batch_id = ${batch.id}
    GROUP BY status, validation_error
    ORDER BY count DESC
    LIMIT 12
  `;
  console.log(JSON.stringify({ batch, failures, candidates }, null, 2));
} finally {
  await sql.end();
}
