{"command":"@'
import dotenv from 'dotenv';
import postgres from 'postgres';

dotenv.config({ path: '.env.local', override: true });
const sql = postgres(process.env.DIRECT_URL!, { max: 1, prepare: false });
const batchId = 'a8a40b72-8b84-49a5-9dd6-b81ff826b78e';
const counts = await sql`
  select status, count(*)::int as count
  from extraction_candidates
  where extraction_batch_id = ${batchId}
  group by status
  order by status
`;
console.log('candidateStatusCounts');
for (const row of counts) console.log(JSON.stringify(row));
const validation = await sql`
  select evr.check_name, evr.status, count(*)::int as count
  from extraction_validation_results evr
  join extraction_candidates ec on ec.id = evr.candidate_id
  where ec.extraction_batch_id = ${batchId}
  group by evr.check_name, evr.status
  order by evr.check_name, evr.status
`;
console.log('validationCounts');
for (const row of validation) console.log(JSON.stringify(row));
const examples = await sql`
  select ec.id, ec.status, ec.summary, ec.domains, left(ece.exact_quote_provided, 260) as quote, ece.validation_status, ece.validation_error,
    array_agg(evr.check_name || ':' || evr.status || ':' || coalesce(left(evr.detail, 180), '')) filter (where evr.id is not null) as checks
  from extraction_candidates ec
  left join extraction_candidate_evidence ece on ece.candidate_id = ec.id
  left join extraction_validation_results evr on evr.candidate_id = ec.id
  where ec.extraction_batch_id = ${batchId}
  group by ec.id, ec.status, ec.summary, ec.domains, ece.exact_quote_provided, ece.validation_status, ece.validation_error
  order by ec.created_at asc
  limit 12
`;
console.log('examples');
for (const row of examples) console.log(JSON.stringify(row));
await sql.end();
'@ | pnpm exec tsx","workdir":"D:\repos\oracle","timeout_ms":120000}

