  select c.id, c.status, c.summary, c.claim_type, c.impact_score, c.confidence_score, left(ce.exact_quote, 220) as quote
  from claims c
  join claim_evidence ce on ce.claim_id = c.id
  where ce.source_document_chunk_id in (select id from document_chunks where document_id = ${documentId})
  order by c.created_at desc
  limit 12
`;
console.log('samples');
for (const row of samples) console.log(JSON.stringify(row));
