{"command":"@'
import dotenv from 'dotenv';
import postgres from 'postgres';

dotenv.config({ path: '.env.local', override: true });
const sql = postgres(process.env.DIRECT_URL!, { max: 1, prepare: false });
const documentId = 'ee1fa682-9e5c-4cf5-89c5-b2f95d047eea';
await sql.begin(async (tx) => {
  const claimRows = await tx`
    select distinct c.id
    from claims c
    join claim_evidence ce on ce.claim_id = c.id
    join document_chunks dc on dc.id = ce.source_document_chunk_id
    where dc.document_id = ${documentId}
  `;
  const claimIds = claimRows.map((r) => r.id);
  if (claimIds.length > 0) {
    await tx`update extraction_candidates set promoted_to_claim_id = null, promoted_at = null, status = 'rejected', review_reason = coalesce(review_reason, 'Removed before full-document reprocess') where promoted_to_claim_id = any(${claimIds}::uuid[])`;
    await tx`update extraction_candidates set duplicate_of_claim_id = null where duplicate_of_claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from claim_entities where claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from claim_metadata where claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from claim_sub_topics where claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from claim_top_domains where claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from claim_domains where claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from section_claims where claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from claim_evidence where claim_id = any(${claimIds}::uuid[])`;
    await tx`delete from claims where id = any(${claimIds}::uuid[])`;
  }
  const evidenceRows = await tx`
    select ece.id, ece.candidate_id
    from extraction_candidate_evidence ece
    join document_chunks dc on dc.id = ece.source_document_chunk_id
    where dc.document_id = ${documentId}
  `;
  const evidenceIds = evidenceRows.map((r) => r.id);
  const candidateIds = [...new Set(evidenceRows.map((r) => r.candidate_id))];
  if (evidenceIds.length > 0) await tx`delete from extraction_validation_results where candidate_evidence_id = any(${evidenceIds}::uuid[])`;
  if (candidateIds.length > 0) {
    await tx`delete from extraction_validation_results where candidate_id = any(${candidateIds}::uuid[])`;
    await tx`delete from extraction_candidate_evidence where candidate_id = any(${candidateIds}::uuid[])`;
    await tx`delete from extraction_candidates where id = any(${candidateIds}::uuid[])`;
  }
  const chunkRows = await tx`select id from document_chunks where document_id = ${documentId}`;
  const chunkIds = chunkRows.map((r) => r.id);
  if (chunkIds.length > 0) {
    await tx`delete from document_chunk_entities where document_chunk_id = any(${chunkIds}::uuid[])`;
    await tx`delete from document_chunk_top_domains where document_chunk_id = any(${chunkIds}::uuid[])`;
  }
  await tx`delete from document_top_domains where document_id = ${documentId}`;
  const deletedChunks = await tx`delete from document_chunks where document_id = ${documentId} returning id`;
  const updated = await tx`
    update documents
    set status = 'pending_processing', processing_error = null, processed_at = null
    where id = ${documentId}
    returning id, status, processed_at, processing_error
  `;
  console.log(JSON.stringify({ claimsDeleted: claimIds.length, evidenceRows: evidenceRows.count, candidateRows: candidateIds.length, chunksDeleted: deletedChunks.count, updated: updated[0] }));
});
await sql.end();
